steps.script:
for nm in ["scn_ig_A", "scn_ig_B"]:
	SaveLoadManager.save_game(nm, {})
return SaveLoadManager.get_save_files().size() >= 2

var d = tree.current_scene.save_load_dialog
var fo = tree.root.get_viewport().gui_get_focus_owner()
var inside = false
var n = fo
while n != null:
	if n == d: inside = true
	n = n.get_parent()
return inside and (fo is ItemList)

var d = tree.current_scene.save_load_dialog
var sel = d.saves_list.get_selected_items()
return sel.size() == 1 and sel[0] == 1 and (tree.root.get_viewport().gui_get_focus_owner() is ItemList)

for nm in ["scn_ig_A", "scn_ig_B"]:
	SaveLoadManager.delete_save_file(nm)
return true
